import{_ as s,C as r,o as i,c as h,a4 as o,E as a,j as d,a as g}from"./chunks/framework.BybBnFXO.js";const T=JSON.parse('{"title":"分级","description":"","frontmatter":{},"headers":[],"relativePath":"zh/grading/intro.md","filePath":"zh/grading/intro.md","lastUpdated":1784099707000}'),b={name:"zh/grading/intro.md"};function p(u,t,c,_,q,m){const e=r("ColorGradeTable"),n=r("ClarityScale"),l=r("ColorWheel");return i(),h("div",null,[t[0]||(t[0]=o('<h1 id="分级" tabindex="-1">分级 <a class="header-anchor" href="#分级" aria-label="Permalink to &quot;分级&quot;">​</a></h1><blockquote><p><em>克拉、颜色、净度、切工——决定价格的四项度量。</em></p></blockquote><p>宝石分级通过标准化标尺评估宝石，让买卖双方可跨地域、跨时间比较。两大主流系统是 GIA 4Cs（用于钻石）和 hue/tone/saturation 三维模型（用于有色宝石）。</p><h2 id="gia-4cs-钻石" tabindex="-1">GIA 4Cs（钻石） <a class="header-anchor" href="#gia-4cs-钻石" aria-label="Permalink to &quot;GIA 4Cs（钻石）&quot;">​</a></h2><p>由美国宝石学院（GIA）于 1953 年建立的 4Cs 框架，是全球钻石分级标准。</p><h3 id="克拉-重量" tabindex="-1">克拉（重量） <a class="header-anchor" href="#克拉-重量" aria-label="Permalink to &quot;克拉（重量）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>单位</th><th>克</th><th>备注</th></tr></thead><tbody><tr><td>1 克拉 (ct)</td><td>0.2 g</td><td>行业标准单位</td></tr><tr><td>1 分 (pt)</td><td>0.01 ct = 0.002 g</td><td>用于亚克拉宝石</td></tr></tbody></table><p>价格随重量呈指数增长，因为大颗粒原石呈指数级稀缺。</p><h3 id="颜色-d-z-等级" tabindex="-1">颜色（D-Z 等级） <a class="header-anchor" href="#颜色-d-z-等级" aria-label="Permalink to &quot;颜色（D-Z 等级）&quot;">​</a></h3>',9)),a(e,{locale:"zh"}),t[1]||(t[1]=d("p",null,'D = 绝对无色（最稀有、最贵）。Z = 浅黄或浅褐色调，仍属于"正常"钻石颜色范围。',-1)),t[2]||(t[2]=d("h3",{id:"净度-fl–i3-等级",tabindex:"-1"},[g("净度（FL–I3 等级） "),d("a",{class:"header-anchor",href:"#净度-fl–i3-等级","aria-label":'Permalink to "净度（FL–I3 等级）"'},"​")],-1)),a(n,{locale:"zh"}),t[3]||(t[3]=o('<p>内含物和瑕疵在 10 倍放大下评估。FL 到 VVS 视为肉眼干净；SI 级别在 10 倍下可见内含物；I 级别肉眼可见内含物。</p><h3 id="切工-质量" tabindex="-1">切工（质量） <a class="header-anchor" href="#切工-质量" aria-label="Permalink to &quot;切工（质量）&quot;">​</a></h3><p>区别于形状（圆、公主方、椭圆等）。切工等级评估比例、对称性和抛光：</p><table tabindex="0"><thead><tr><th>等级</th><th>描述</th></tr></thead><tbody><tr><td><strong>Excellent（极好）</strong></td><td>反射几乎所有入射光，最大火彩与闪耀</td></tr><tr><td><strong>Very Good（很好）</strong></td><td>反射大部分光线；亭部有少量损失</td></tr><tr><td><strong>Good（好）</strong></td><td>可接受的闪耀；有少量光泄漏</td></tr><tr><td><strong>Fair（一般）</strong></td><td>可见光泄漏；外观暗淡</td></tr><tr><td><strong>Poor（差）</strong></td><td>大部分光逃逸；石头显暗或玻璃状</td></tr></tbody></table><h2 id="有色宝石分级" tabindex="-1">有色宝石分级 <a class="header-anchor" href="#有色宝石分级" aria-label="Permalink to &quot;有色宝石分级&quot;">​</a></h2><p>有色宝石（红宝石、蓝宝石、祖母绿等）使用基于三个维度的不同系统：</p><h3 id="色调-hue" tabindex="-1">色调（Hue） <a class="header-anchor" href="#色调-hue" aria-label="Permalink to &quot;色调（Hue）&quot;">​</a></h3>',7)),a(l,{locale:"zh"}),t[4]||(t[4]=o('<p>色调 = 基本颜色（红、绿、蓝等）位于色相轮上的位置。</p><h3 id="色调-tone-明度" tabindex="-1">色调（Tone，明度） <a class="header-anchor" href="#色调-tone-明度" aria-label="Permalink to &quot;色调（Tone，明度）&quot;">​</a></h3><p>色调是白到黑尺度上的位置。分类为：</p><ul><li><strong>很浅</strong>（0–20% 灰）</li><li><strong>浅</strong>（20–40%）</li><li><strong>中浅</strong>（40–60%）</li><li><strong>中</strong>（60%）</li><li><strong>中深</strong>（60–80%）</li><li><strong>深</strong>（80–90%）</li><li><strong>很深</strong>（90–100%）</li></ul><p>色相轮的中央圆盘表示色调，从顶部浅到底部深渐变。</p><h3 id="饱和度-saturation" tabindex="-1">饱和度（Saturation） <a class="header-anchor" href="#饱和度-saturation" aria-label="Permalink to &quot;饱和度（Saturation）&quot;">​</a></h3><p>饱和度描述颜色纯度：</p><ul><li><strong>淡</strong> — 柔和，低彩度</li><li><strong>适中</strong> — 清晰颜色</li><li><strong>鲜艳</strong> — 强烈、纯净</li><li><strong>浓</strong> — 卓越颜色</li><li><strong>深</strong> — 极深浓郁</li></ul><blockquote><p>对于大多数有色宝石，<strong>鲜艳 / 浓</strong> 的组合溢价最高。一颗鲜艳红宝石的价值可能是等克拉暗红宝石的 50 倍。</p></blockquote><h2 id="处理披露" tabindex="-1">处理披露 <a class="header-anchor" href="#处理披露" aria-label="Permalink to &quot;处理披露&quot;">​</a></h2><p>实验室手册协调委员会（LMHC）标准化了宝石报告中处理方式的披露。常见披露处理包括：</p><table tabindex="0"><thead><tr><th>处理</th><th>常见于</th><th>披露</th></tr></thead><tbody><tr><td><strong>热处理</strong></td><td>红宝石、蓝宝石、坦桑石</td><td>普遍接受</td></tr><tr><td><strong>填充（油/树脂）</strong></td><td>祖母绿</td><td>行业标准用于裂隙</td></tr><tr><td><strong>HPHT</strong></td><td>钻石</td><td>需披露</td></tr><tr><td><strong>辐照</strong></td><td>蓝色托帕石、部分电气石</td><td>需披露</td></tr><tr><td><strong>扩散处理</strong></td><td>蓝宝石（表面颜色）</td><td>需披露</td></tr><tr><td><strong>涂层</strong></td><td>各类</td><td>需披露</td></tr></tbody></table><p>未处理宝石溢价显著。LMHC 推荐披露语言：&quot;无热处理迹象&quot;（NTE）。</p><h2 id="产地溢价" tabindex="-1">产地溢价 <a class="header-anchor" href="#产地溢价" aria-label="Permalink to &quot;产地溢价&quot;">​</a></h2><p>对于部分宝石，地理来源显著影响价值：</p><table tabindex="0"><thead><tr><th>宝石</th><th>溢价产地</th><th>普通产地</th></tr></thead><tbody><tr><td><strong>红宝石</strong></td><td>缅甸（抹谷、孟休）</td><td>莫桑比克、泰国</td></tr><tr><td><strong>蓝宝石</strong></td><td>克什米尔、缅甸</td><td>斯里兰卡、马达加斯加</td></tr><tr><td><strong>祖母绿</strong></td><td>哥伦比亚（木佐、契沃尔）</td><td>赞比亚、巴西</td></tr><tr><td><strong>亚历山大石</strong></td><td>俄罗斯（乌拉尔）</td><td>巴西、斯里兰卡</td></tr><tr><td><strong>帕拉伊巴碧玺</strong></td><td>巴西（帕拉伊巴州）</td><td>莫桑比克、尼日利亚</td></tr><tr><td><strong>坦桑石</strong></td><td>坦桑尼亚（梅雷拉尼）</td><td>（单一来源）</td></tr></tbody></table><p>产地判定需要精细的微量元素分析（LA-ICP-MS），可能需要与已知来源的参考宝石比对。</p><h2 id="如何阅读分级报告" tabindex="-1">如何阅读分级报告 <a class="header-anchor" href="#如何阅读分级报告" aria-label="Permalink to &quot;如何阅读分级报告&quot;">​</a></h2><p>典型实验室报告包括：</p><ol><li><strong>鉴定</strong> — 种类和变种</li><li><strong>重量</strong> — 克拉，精确到小数点后 2 位</li><li><strong>尺寸</strong> — 长 × 宽 × 深 (毫米)</li><li><strong>颜色等级</strong> — 字母（D-Z）+ 彩色描述</li><li><strong>净度等级</strong> — FL/IF/VVS/VS/SI/I + 子级</li><li><strong>切工等级</strong> — Excellent/Very Good/Good/Fair/Poor</li><li><strong>抛光/对称</strong> — Excellent/Very Good/Good/Fair</li><li><strong>荧光</strong> — None/Faint/Medium/Strong</li><li><strong>备注</strong> — 处理、产地、特殊特征</li><li><strong>编号与实验室标志</strong></li></ol>',20))])}const x=s(b,[["render",p]]);export{T as __pageData,x as default};
